import { useState } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    const selected = e.target.files[0];
    setFile(selected);
    if (selected) {
      setPreview(URL.createObjectURL(selected));
    }
  };

  const handleUpload = async () => {
    if (!file) return alert("Upload an image first");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });

      const data = await response.json();
      setResult(data);
    } catch (error) {
      alert("Server error");
    }

    setLoading(false);
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h1 style={styles.title}>CLAIMPILOT AI</h1>
        <p style={styles.subtitle}>
          Advanced Vehicle Damage Intelligence System
        </p>

        <div style={styles.uploadCard}>
          {preview && (
            <img src={preview} alt="preview" style={styles.previewImage} />
          )}

          <label style={styles.uploadLabel}>
            Upload Damage Image
            <input
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              onChange={handleFileChange}
            />
          </label>

          <button
            onClick={handleUpload}
            disabled={loading}
            style={loading ? styles.buttonLoading : styles.button}
          >
            {loading ? "Analyzing..." : "Run AI Analysis"}
          </button>
        </div>

        {result && (
          <div style={styles.resultPanel}>
            <div style={styles.statBox}>
              <h3>💰 Estimate</h3>
              <p>PKR {result.total_estimate_pkr}</p>
            </div>

            <div style={styles.statBox}>
              <h3>🧠 Fraud Score</h3>
              <p>{result.fraud_confidence_score}</p>
            </div>

            <div style={styles.statBox}>
              <h3>⚖ Verdict</h3>
              <p>{result.verdict}</p>
            </div>

            <div style={styles.fullWidth}>
              <h3>Fraud Analysis</h3>
              <p>{result.fraud_analysis}</p>

              <h3>Damaged Parts</h3>
              <ul>
                {result.damaged_parts?.map((part, index) => (
                  <li key={index}>{part}</li>
                ))}
              </ul>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background:
      "linear-gradient(270deg, #0f2027, #203a43, #2c5364)",
    backgroundSize: "600% 600%",
    animation: "gradientMove 10s ease infinite",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
    fontFamily: "Segoe UI, sans-serif",
  },

  container: {
    width: "100%",
    maxWidth: "900px",
    color: "white",
    textAlign: "center",
  },

  title: {
    fontSize: "42px",
    letterSpacing: "3px",
    marginBottom: "10px",
    textShadow: "0 0 20px #00f2ff",
  },

  subtitle: {
    opacity: 0.7,
    marginBottom: "40px",
  },

  uploadCard: {
    background: "rgba(255,255,255,0.05)",
    backdropFilter: "blur(20px)",
    padding: "30px",
    borderRadius: "20px",
    marginBottom: "40px",
    boxShadow: "0 0 40px rgba(0,255,255,0.2)",
  },

  previewImage: {
    width: "100%",
    maxHeight: "300px",
    objectFit: "cover",
    borderRadius: "15px",
    marginBottom: "20px",
  },

  uploadLabel: {
    display: "block",
    padding: "15px",
    border: "2px dashed #00f2ff",
    borderRadius: "12px",
    cursor: "pointer",
    marginBottom: "20px",
    transition: "0.3s",
  },

  button: {
    padding: "15px 40px",
    borderRadius: "30px",
    border: "none",
    background: "linear-gradient(90deg,#00f2ff,#4facfe)",
    color: "#000",
    fontWeight: "700",
    cursor: "pointer",
    transition: "0.3s",
  },

  buttonLoading: {
    padding: "15px 40px",
    borderRadius: "30px",
    border: "none",
    background: "#666",
    color: "#fff",
  },

  resultPanel: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(250px,1fr))",
    gap: "20px",
  },

  statBox: {
    background: "rgba(255,255,255,0.05)",
    padding: "20px",
    borderRadius: "15px",
    boxShadow: "0 0 20px rgba(0,255,255,0.2)",
  },

  fullWidth: {
    gridColumn: "1 / -1",
    background: "rgba(255,255,255,0.05)",
    padding: "20px",
    borderRadius: "15px",
  },
};

export default App;
